import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import aaImage from '../aa.jpg'; // ✅ Use same background as Login

const Register = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5000/api/auth/register', { email, password });
      alert('Registered successfully!');
      navigate('/'); // redirect to login
    } catch (err: any) {
      console.error(err);
      setError(err.response?.data?.message || 'Registration failed!');
    }
  };

  return (
    <div
      style={{
        backgroundImage: `url(${aaImage})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
      }}
    >
      <div
        style={{
          backgroundColor: 'rgba(0, 0, 0, 0.85)',
          padding: '40px',
          borderRadius: '10px',
          width: '400px',
          color: 'white',
          boxShadow: '0 0 10px rgba(0, 0, 0, 0.5)',
        }}
      >
        <h2 style={{ textAlign: 'center', marginBottom: '20px' }}>
          🎬 Create your Movie App account
        </h2>
        <p style={{ textAlign: 'center', color: '#ccc' }}>Start watching your favorites</p>

        {error && <p style={{ color: 'red', textAlign: 'center' }}>{error}</p>}

        <form onSubmit={handleRegister}>
          <label htmlFor="email">Email address</label>
          <input
            id="email"
            type="email"
            placeholder="you@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            style={inputStyle}
          />

          <label htmlFor="password">Password</label>
          <input
            id="password"
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            style={inputStyle}
          />

          <button type="submit" style={registerBtnStyle}>
            Register
          </button>

          <p style={{ textAlign: 'center', marginTop: '15px', color: '#aaa' }}>
            Already have an account?{' '}
            <span
              onClick={() => navigate('/')}
              style={{ color: 'red', textDecoration: 'underline', cursor: 'pointer' }}
            >
              Login
            </span>
          </p>
        </form>
      </div>
    </div>
  );
};

// 🔁 Reusable styles
const inputStyle: React.CSSProperties = {
  width: '100%',
  padding: '12px',
  margin: '10px 0',
  borderRadius: '6px',
  border: 'none',
  backgroundColor: '#222',
  color: '#fff',
};

const registerBtnStyle: React.CSSProperties = {
  width: '100%',
  padding: '12px',
  backgroundColor: 'red',
  color: '#fff',
  borderRadius: '6px',
  border: 'none',
  fontWeight: 'bold',
  cursor: 'pointer',
  marginTop: '10px',
};

export default Register;
